.darma-loader-uiverse-redirect-meter-card {
  width: 260px;
  height: 135px;
  border-radius: 14px;
  background: #ffffff;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-evenly;
  padding: 24px;
  box-shadow: 2px 2px 18px -8px #94a3b8;
}
.darma-loader-uiverse-redirect-meter-card__loading { width: 100%; height: 10px; background: var(--loader-secondary-color, #d9d9d9); border-radius: 10px; position: relative; overflow: hidden; }
.darma-loader-uiverse-redirect-meter-card__loading::after { content: ""; position: absolute; top: 0; left: 0; width: 50%; height: 10px; background: var(--loader-color, #000022); border-radius: 10px; animation: darma-loader-uiverse-redirect-meter-card-redirectBar .7s alternate infinite; }
.darma-loader-uiverse-redirect-meter-card__label { color: var(--loader-color, #000022); font-size: 18px; font-weight: 700; animation: darma-loader-uiverse-redirect-meter-card-redirectBlink .7s alternate infinite; }
@keyframes darma-loader-uiverse-redirect-meter-card-redirectBlink { from { opacity: .35; } to { opacity: 1; } }
@keyframes darma-loader-uiverse-redirect-meter-card-redirectBar { from { left: 0%; } to { left: 50%; } }

